const hasRenderableValue = (value?: ReactNode) => {
  if (typeof value === 'number') {
    return true;
  }

  if (typeof value === 'string') {
    return value.trim().length > 0;
  }

  if (Array.isArray(value)) {
    return value.length > 0;
  }

  return !!value;
};

const formatBankAccountLabel = (bankAccount: BankAccount) => {
  const typeLabel =
    bankAccount.accountType === 'savings'
      ? 'Savings'
      : bankAccount.accountType === 'checking'
        ? 'Checking'
        : undefined;
  const accountDigits = bankAccount.accountNumber?.slice(-4);
  const nickname = bankAccount.nickname || typeLabel;
  const parts = [
    bankAccount.bankName ?? 'Bank account',
    nickname ? `• ${nickname}` : null,
    accountDigits ? `• ••••${accountDigits}` : null,
  ].filter((segment): segment is string => typeof segment === 'string');

  return parts.join(' ');
};

const formatDocumentLabel = (documentType: DocumentType) =>
  DOCUMENT_LABELS[documentType] ??
  documentType
    .split('_')
    .map((segment) => segment.toUpperCase())
    .join(' ');

const createField = (
  label: string,
  value?: ReactNode,
  options?: { isPresent?: boolean; isRequired?: boolean }
): SummaryField => {
  const shouldMarkMissing =
    options?.isRequired && !(options?.isPresent ?? hasRenderableValue(value));

  return {
    isMissing: shouldMarkMissing,
    label,
    value,
  };
};

