import { AccountDocumentType, DocumentCategory } from '@domain/accountDocument';
import * as documentService from '@service/anedot/accountDocuments';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { FileUpload, useFileUploader } from '@state/utils';
import { toBase64 } from '@utils/toBase64/toBase64';
import { useEffect } from 'react';
import { useFormContext } from 'react-hook-form';

type Params = {
  documentCategory: DocumentCategory;
  documentType: AccountDocumentType;
  initialUploads: FileUpload[];
};

export const useDocumentationUploader = ({
  documentCategory,
  documentType,
  initialUploads,
}: Params) => {
  const { currentAccount } = useGetAccount();

  const { refreshCache } = useCacheHelper(resourceKeys.accountDocuments);

  const { clearErrors, setValue } = useFormContext();

  const { addFile, haveCompletedAllUploads, removeFile, uploads } = useFileUploader({
    deleter: (id) => {
      return documentService.destroy({
        accountId: currentAccount?.id as string,
        documentId: id,
      });
    },
    initialUploads,
    uploader: async (file, signal, onUploadProgress) => {
      const fileString = await toBase64(file);

      const result = await documentService.create(
        {
          accountId: currentAccount?.id as string,
          documentName: file.name,
          documentType,
          file: fileString,
        },
        { onUploadProgress, signal }
      );

      return result;
    },
  });

  const addFileWithRefresh = (body: File) => {
    addFile(body, {
      onSuccess: () => {
        clearErrors(documentCategory);
        setValue(documentCategory, true, {
          shouldDirty: true,
          shouldValidate: true,
        });

        return refreshCache('');
      },
    });
  };

  const removeFileWithRefresh = (body: File) => {
    removeFile(body, {
      onSuccess: () => {
        setValue(documentCategory, false, {
          shouldDirty: true,
          shouldValidate: true,
        });

        return refreshCache('');
      },
    });
  };

  useEffect(() => {
    setValue(
      documentCategory,
      uploads.some((upload) => upload.status === 'complete'),
      {
        shouldValidate: true,
      }
    );
  }, [documentCategory, setValue, uploads]);

  return {
    addFile: addFileWithRefresh,
    haveCompletedAllUploads,
    removeFile: removeFileWithRefresh,
    uploads,
  };
};

