export function getRequiredDocumentCategoriesByRequiredDocuments(
  requiredDocuments: string[]
): Partial<Record<DocumentCategory, AccountDocumentType[]>> {
  const requiredDocCategories: Partial<Record<DocumentCategory, AccountDocumentType[]>> = {};
  for (const requiredDocument of requiredDocuments) {
    if (hasKey(DOCUMENTS_BY_DOC_CATEGORY, requiredDocument)) {
      requiredDocCategories[requiredDocument] = [...DOCUMENTS_BY_DOC_CATEGORY[requiredDocument]];
    }
  }
